@@ -2190,4 +2196,31 @@ public class DeserializationContext
     protected String _shapeForToken(JsonToken t) {
         return JsonToken.valueDescFor(t);
     }
+
+    /**
+     * Helper method that walks the current TokenStreamContext stack
+     * and prepends each named path segment onto the given exception.
+     */
+    protected void _prependContextPath(MismatchedInputException e) {
+        final JsonParser p = _parser;
+        if (p == null) {
+            return;
+        }
+        TokenStreamContext ctx = p.streamReadContext();
+        while (ctx != null && !ctx.inRoot()) {
+            if (ctx.inObject() && ctx.hasCurrentName()) {
+                String name = ctx.currentName();
+                if (name != null) {
+                    e.prependPath(null, name);
+                }
+            } else if (ctx.inArray()) {
+                e.prependPath(null, ctx.getCurrentIndex());
+            }
+            ctx = ctx.getParent();
+        }
+    }
